# Utility module with numeric operations and shapes

class Calculator:
    @static
    value: int = 0

    @static
    def reset() -> None:
        Calculator.value = 0

    def add(self, x: int, y: int) -> int:
        return x + y

    def multiply(self, x: int, y: int) -> int:
        return x * y

    @property get current(self) -> int:
        return Calculator.value

class Shape:
    def __init__(self, name: str) -> None:
        self.name = name

    def __str__(self) -> str:
        return f"Shape({self.name})"

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

@abstract
class Polygon(Shape):
    def __init__(self, name: str, sides: int) -> None:
        super().__init__(name)
        self.sides = sides

    def describe(self) -> str:
        return f"{self.name} with {self.sides} sides"

class Rectangle(Polygon):
    def __init__(self, width: float, height: float) -> None:
        super().__init__("Rectangle", 4)
        self.width = width
        self.height = height

    @property get width(self) -> float:
        return self.width

    @property get height(self) -> float:
        return self.height

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def __str__(self) -> str:
        return f"Rectangle({self.width}, {self.height})"

class Circle(Shape):
    def __init__(self, radius: float) -> None:
        super().__init__("Circle")
        self.radius = radius

    @property get radius(self) -> float:
        return self.radius

    def area(self) -> float:
        import math
        return math.pi * self.radius * self.radius

    def perimeter(self) -> float:
        import math
        return 2.0 * math.pi * self.radius

    def __str__(self) -> str:
        return f"Circle({self.radius})"

def process_shapes(shapes: list[Shape]) -> tuple[float, float]:
    total_area: float = 0.0
    total_perimeter: float = 0.0

    i: int = 0
    while i < len(shapes):
        shape: Shape = shapes[i]
        total_area = total_area + shape.area()
        total_perimeter = total_perimeter + shape.perimeter()
        i = i + 1

    return (total_area, total_perimeter)

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

def fibonacci(n: int) -> int:
    a: int = 0
    b: int = 1
    i: int = 0
    while i < n:
        temp: int = a + b
        a = b
        b = temp
        i = i + 1
    return a
